// Services.jsx
import React from 'react';
import ServicesDiamond from '../components/ServicesDiamond';
const cards = [
  {
    id: 'card1',
    src: 'C:\Users\Sarrdeh Tech\sarrdeh-react\public\images\chart.svg',
    alt: 'Frame 411',
    title: 'Frame 411 | SarrdehTech',
  },
  {
    id: 'card2',
    src: 'https://www.sarrdeh-tech.com/wp-content/uploads/2025/05/Frame-488.png',
    alt: 'Frame 488',
    title: 'Frame 488 | SarrdehTech',
  },
  {
    id: 'card3',
    src: 'https://www.sarrdeh-tech.com/wp-content/uploads/2025/05/Frame-412.png',
    alt: 'Frame 412',
    title: 'Frame 412 | SarrdehTech',
  },
];

const Services = () => (
  <div
    className="row row-collapse align-equal align-center cards-wrapper"
    style={{ position: 'relative' }}
  >
    {cards.map(card => (
      <div
        key={card.id}
        className={`col ${card.id} medium-6 small-12 large-6`}
        style={{
          position: 'absolute',
          top: '50%',
          left: '50%',
          transform: 'translate(-50%, -50%)',
          willChange: 'transform',
        }}
      >
        <div className="col-inner text-center">
          <ServicesDiamond
            src={card.src}
            alt={card.alt}
            title={card.title}
            className=""             
          />
        </div>
      </div>
    ))}
  </div>
);

export default Services;
